var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"휴…. 이걸로 일단 한숨 돌릴 수 있겠어.","JPN":"ふう……これで一息つける。","ENG":"Phew... That's one thing off my list.","TWN":"呼…這樣應該可以稍微喘口氣吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아직 시간 남았으니까 조금 쉬었다가……","JPN":"まだ時間があるし、ちょっと休んでから……","ENG":"There's still time left, so maybe I'll rest a little–","TWN":"還有點時間，先休息一下再……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":" 음?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L6_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"이사장님~","JPN":"理事長～","ENG":"Ms. Chairwoman!","TWN":"理事長～"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이사장님~ 트릭 오어 트릿!","JPN":"理事長～トリック・オア・トリート！","ENG":"Ms. Chairwoman! Trick or treat!","TWN":"理事長～不給糖就搗蛋！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"저번에 할로윈날에 찾아오면 과자 준다고 하셔서 찾아왔어요!","JPN":"この前、ハロウィンの日に来たらお菓子くれるって言ってたから来ました！","ENG":"You promised to give us snacks this Halloween, so we're here!","TWN":"上次你說萬聖節的時候來找你的話，你會給我們糖果喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"얘들아. 갑자기 들어가면 실례잖아.","JPN":"ちょっと。いきなり入るなんて失礼でしょ。","ENG":"Sky, it's rude to barge in like that.","TWN":"你們這樣突然闖進去是很沒禮貌的喔。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"죄송해요. 많이 놀라셨죠?","JPN":"ごめんなさい。驚かれましたよね？。","ENG":"I'm sorry. Did we startle you?","TWN":"理事長對不起，嚇到你了吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"괜찮아. 편하게 놀러 오라고 했던 건 나인걸?","JPN":"大丈夫よ。気兼ねなく遊びに来てって言ったのは私なんだから。","ENG":"It's fine. I'm the one who told you that you're welcome anytime.","TWN":"沒事，是我說你們可以來這裡玩的。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"어디 보자… 너희들이 좋아할 만한 과자는…….","JPN":"それじゃあ……あなたたちが好きそうなお菓子は……","ENG":"Now, lemme see here... What would you girls like...","TWN":"我看看喔…你們會喜歡的糖果是……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기… 일하시는데 정말 괜찮을까요?","JPN":"あの……お仕事してるのに、本当に大丈夫なんですか？","ENG":"Uh... are you sure it's okay while you're working?","TWN":"理事長…真的沒關係嗎？你不是在工作嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"후후후… 안 괜찮으셔도 괜찮습니다.","JPN":"ふふふ……大丈夫じゃなくても大丈夫なのです。","ENG":"Fu fu fu... It's okay even if you're not.","TWN":"呵呵呵…有關係也沒關係。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"마침 새로 개발한 10초 만에 피로회복을 사용해 볼 때가 온 것 같군요!","JPN":"まさに新しく開発した、「10秒で疲労回復くん」の出番みたいですね！","ENG":"I think the time has come to test my newly developed \\"10-second Fatigue Relief!\\"","TWN":"正好我想試試看我新開發的10秒內即刻恢復效果如何！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"히어로는 항상 피곤할 테니까, 이런 기계도 유용하지 않을까 했거든요.","JPN":"ヒーローはいつもお疲れだろうから、こんな機械も役立つはずでは？　と思ったんです。","ENG":"Heroes are always exhausted, so I thought a device like this will come in handy.","TWN":"英雄常常都很累，這個機器應該會派上用場吧！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"안 돼. 그거 예전에 스카이가 졸고 있을 때 빼고 한 번도 안 써본 거잖아.","JPN":"ダメ。それ、この前スカイが居眠りしてた時以外、一度も使ったことないでしょ？","ENG":"No. You used that on Sky when she was dozing off and never used it again.","TWN":"不可以，那個只有之前在絲凱打瞌睡的時候測試過一次而已。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"자, 어서 나가자 얘들아.","JPN":"はい、みんな。早く出よう。","ENG":"Now, let's stop bothering her, girls.","TWN":"我們快點出去吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너희들 그거 아니? 이사장실에 함부로 들어온 학생들은 모두 어떻게 되었는지.","JPN":"あなたたち、知ってる？　理事長室に許可もなく入ってきた生徒たちが、どうなったのかを。","ENG":"Don't you know what happens to kids that barge into the chairwoman's office?","TWN":"你們知道嗎？隨便闖入理事長辦公室的學生會有什麼下場？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"내가 대접하는 과자를 마음껏 먹을 때까지 단 한 사람도 빠져나가지 못했단다.","JPN":"私が出すお菓子をお腹いっぱい食べるまで、誰もここから出られなかったのよ。","ENG":"None of them could leave until they were completely full from all the snacks I served.","TWN":"必須要把我招待的餅乾全部吃完才可以離開。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"자, 어서 앉으렴. 이번 신상품인데 이 초코 바닐라 밀페유부터 먹어볼래?","JPN":"はい、早く座りなさい。新商品なんだけど、このチョコバニラミルフィーユから食べてみる？","ENG":"Now, sit down. Why don't you all try the new chocolate vanilla pastry?","TWN":"都快坐下，這次有新產品喔。從這個香草巧克力千層派開始吃嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저, 정말요?","JPN":"ほ、本当ですか？","ENG":"R-really?","TWN":"真，真的嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"우와아~ 잘 먹겠습니다!","JPN":"うわあ～いただきます！","ENG":"Wow! Thank you!","TWN":"哇～～謝謝理事長！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L34_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"음~ 정말 맛있어요!","JPN":"う～ん、とっても美味しいです！","ENG":"Mm...! It's so delicious!","TWN":"嗯～～好好吃喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"보통 단맛은 계속 먹다 보면 물리기도 하는데 이런 건 처음이야.","JPN":"甘いものは食べてると飽きるもんだけど、こんなのは初めてだ。","ENG":"I usually get sick of eating sweet things after a while, but this is a first.","TWN":"通常甜的東西吃多就會膩，第一次吃到這種不會膩的欸。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"세상의 모든 과자를 다 가지고 있다는 소문은 역시 사실이었네요.","JPN":"世界中のお菓子がここにあるってウワサは、やっぱり本当だったんですね。","ENG":"The rumors were true about how you have all the world's snacks.","TWN":"傳言說理事長有世界各國的餅乾，看來是真的！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 친구들이 자주 보내주거든.","JPN":"ふふっ、友だちがよく送ってくれるの。","ENG":"Ha ha. My friends send them to me frequently.","TWN":"呵呵，因為朋友常常送給我啦。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너희들이 많이 먹어줘서 정말 기뻐. 할로윈이 아니더라도 자주 찾아오렴.","JPN":"あなたたちがたくさん食べてくれて本当に嬉しいわ。ハロウィンじゃなくても、もっと遊びに来なさい。","ENG":"I'm glad to see that you're enjoying them. Come visit more often even when it's not Halloween.","TWN":"看你們吃得開心，我也很開心。就算不是萬聖節，也可以常來喔。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기…. 이사장님. 전부터 생각했는데 여기가 정말 이사장실이 맞나요?","JPN":"あの……理事長。前から思ってたんですけど、ここって本当に理事長室なんですか？","ENG":"Um... Ms. Chairwoman? I've been thinking about this for a while now, but is this really your office?","TWN":"那個…理事長。我從以前就覺得有點疑問，這裡真的是理事長辦公室嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"책에서 봤는데 옛날 교실의 모습이 여기 이사장실과 똑같은 것 같아서요.","JPN":"本で見たんですけど、昔の教室がこの理事長室とそっくりだったんです。","ENG":"I saw it in a book once, and the old classroom looked exactly like your office.","TWN":"我在書上看過以前的舊教室，長得就和理事長辦公室一模一樣呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"맞아요. 그래서 이 교실은 위장이고, 사실 어딘가 비밀 기지가 숨겨져 있을거라 생각했죠.","JPN":"そうだよ。だからこの理事長室は偽りで、実はどこかに秘密基地が隠れてるんだって思ってました。","ENG":"Yeah. We were thinking that this classroom is just a disguise and there is actually a secret base hidden somewhere here.","TWN":"對啊，我們都覺得這裡是假的，真正的辦公室藏在其他地方。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"낮에는 이사장으로서 조용히 지내지만, 밤이 오면 히어로로 활동하는 이중생활!","JPN":"昼間は理事長として過ごし、夜はヒーローとして活動する二重生活！","ENG":"Living a double life of a chairwoman in the morning and a hero at night!","TWN":"其實你有雙重身分，白天是理事長，晚上就會變身成超級英雄！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 재밌는 생각이네.","JPN":"あはは、面白い考え方ね。","ENG":"Ah hah hah, that's an interesting thought.","TWN":"哈哈哈，你們真有趣。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"여긴 내가 어렸을 때 다녔던 교실을 그대로 디자인한 거야.","JPN":"ここは私が小さい頃に通ってた教室をそのままデザインしたの。","ENG":"I designed this office to look like the classroom from when I attended school.","TWN":"我刻意把這裡設計成和我小時候的教室一樣。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그때 시절이 너무 좋았거든…….","JPN":"あの頃が本当に大好きだったから……","ENG":"I just loved that time of my life...","TWN":"因為那時是我最開心的時光……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"와~ 저 뒤에 있는 그림이 이사장님 친구분들인가요?","JPN":"わあ～あの後ろにある絵が理事長のお友だちなんですか？","ENG":"Wow! Are those portraits back there of your friends?","TWN":"哇～後面那張照片裡的人就是理事長的朋友嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"투박하지만 특징이 잘 잡혀있네요.","JPN":"大雑把な絵だけど、ちゃんと特徴をおさえていますね。","ENG":"It's a little rough, but their characteristics are well-defined.","TWN":"雖然畫得有點粗糙，但特色都有抓到呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"오른쪽 밑에 사람이 이사장님 맞죠?","JPN":"右下の人が理事長ですよね？","ENG":"The person on the bottom right is you, right, Ms. Chairwoman?","TWN":"右下方那個是理事長對吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"맞아. 정말 예리한걸?","JPN":"そうよ。本当に鋭いわね。","ENG":"Correct. What a keen eye you have!","TWN":"沒錯，你的觀察力很好呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"오?! 저 <color=#ffd34c>로봇 마스크</color>를 쓴 사람은 누군가요?","JPN":"おっ！？　あの<color=#ffd34c>ロボットのマスク</color>を被ってる人は誰ですか？","ENG":"Oh?! Who's the one with the <color=#ffd34c>robot mask</color>?","TWN":"嗯？那個戴著<color=#ffd34c>機器人面具</color>的是誰啊？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"설마 진짜로 히어로 친구가 있으셨던 건가요?","JPN":"まさか、本当にヒーローの友だちがいたんですか？","ENG":"Did you really have a hero friend?","TWN":"該不會你的朋友真的是超級英雄吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아, 저 애는…….","JPN":"あ、あの子は……","ENG":"Oh, he...","TWN":"喔，他喔……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"<color=#ffd34c>최고의 히어로</color>였지. 옛날에 우릴 구해주었단다.","JPN":"<color=#ffd34c>最高のヒーロー</color>だったの。昔、私たちを助けてくれた。","ENG":"He was <color=#ffd34c>the best hero</color>. He saved us all a long time ago.","TWN":"他是<color=#ffd34c>最棒的英雄</color>，他曾經救過我們喔。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"와 정말요? 지금도 친해요? 한번 만나볼 수 있나요?","JPN":"うわ、本当ですか？　今も仲良しですか？　一度会えますか？","ENG":"Really? Are you still close to him? Could we meet him?","TWN":"哇，真的嗎？那你們現在還是很要好嗎？我們可以跟他見個面嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아 그건…….","JPN":"あ、それは……","ENG":"Ah, that's...","TWN":"這個嘛……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이사장님, 슬슬 베타 테스트 시간입니다.","JPN":"理事長、そろそろベータテストの時間です。","ENG":"Ms. Chairwoman, it's almost time for the beta testing.","TWN":"理事長，差不多要進行測試了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"어머, 벌써 시간이 이렇게 됐구나. 정말 미안해.","JPN":"あら、もうこんな時間なのね。本当にごめん。","ENG":"Oh, my. Is it time already? I'm really sorry.","TWN":"哎呀，時間過得真快，真不好意思。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"타이밍이 하필 이렇게 맞아떨어지다니……. 어쩔 수 없죠.","JPN":"よりによってこんなタイミングに……仕方ないですね。","ENG":"The timing couldn't be any worse... But oh, well.","TWN":"還真會挑時間……只好下次再說囉。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"다음에 또 찾아와 주렴. 알겠지?","JPN":"今度また来て。いいわね？","ENG":"Come visit again next time, okay?","TWN":"要再來玩喔？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_PROMISE_NULL_NPC","text":{"KOREA":"오늘이 테스트 날이셨죠?","JPN":"今日はテストの日でしたね？","ENG":"Today's the test day, right?","TWN":"今天是測試的日子吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_PROMISE_NULL_NPC","text":{"KOREA":"아카데미의 이사장과 함께 베타 테스트를 진행하신다니, 소문대로 대단한 인맥이네요.","JPN":"アカデミーの理事長と一緒にベータテストを行うとは、噂どおりすごい人脈ですね。","ENG":"Doing a beta test with the Academy's chairwoman. Your connections weren't just rumors after all.","TWN":"竟然和學院的理事長一起進行測試，你真的如傳言所說的人脈很廣呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_PROMISE_NULL_NPC","text":{"KOREA":"두 분이 함께 협업했다는 건 대단한 뉴스가 되겠어요.","JPN":"お二人の共同作業だなんて、大ニュースになりそうですよ。","ENG":"It'll be a great headliner that you two collaborated as partners.","TWN":"二位一起合作的事一定會上新聞的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"<color=#ffd34c>네 명</color>이에요……. 줄곧 그래왔으니까…….","JPN":"<color=#ffd34c>4人</color>です……ずっとそうだったから……","ENG":"It's <color=#ffd34c>four</color>, actually... It always has been...","TWN":"是<color=#ffd34c>四位</color>……一直都是四位……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"오늘은…… 세 명이지만.","JPN":"今日は……3人だけど。","ENG":"Even if it's only three people... for today.","TWN":"雖然……今天只有三位。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAFF_PROMISE_NULL_NPC","text":{"KOREA":"네? 그게 누구죠?","JPN":"はい？　誰のことですか？","ENG":"Huh? Who are you talking about?","TWN":"蛤？你是說哪位？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"……친구.","JPN":"……友だち。","ENG":"...My friends.","TWN":"……朋友。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"먼저 퇴근하세요……. 오래 걸릴 거예요.","JPN":"先に帰っても大丈夫です……長くなりますから。","ENG":"You can get off work first... This will take some time.","TWN":"你先下班吧……會弄很久。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};